using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a JSON REST API via HttpClient.
/// The SDK injects constructor parameters from DI — they never appear in the tool schema.
/// Only parameters decorated with [Description] are exposed to the LLM.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Retrieve a single resource by its numeric ID.")]
    public async Task<string> GetResource(
        [Description("Numeric ID of the resource to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var json = await httpClient.GetStringAsync($"/posts/{id}", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("List resources, optionally filtered by user ID.")]
    public async Task<string> ListResources(
        [Description("Optional user ID to filter results")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing resources from {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new resource with the given title and body.")]
    public async Task<string> CreateResource(
        [Description("Title of the new resource")] string title,
        [Description("Body content of the new resource")] string body,
        [Description("User ID of the resource author")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource for user {UserId}", userId);
        var payload = new { title, body, userId };
        var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return FormatJson(json);
    }

    private static string FormatJson(string raw)
    {
        using var doc = JsonDocument.Parse(raw);
        return JsonSerializer.Serialize(doc, JsonOptions);
    }
}

